import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting", () => {
    it("should compute base premium for a single sword", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      // base 100 + 10% first insurance = 110 + 5 fee = 115
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should compute base premium for each item type (amulet, staff, potion)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      // base 60 + 10% first insurance = 66 + 5 fee = 71
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it.todo("should compute base premium for a single component (rune)");
    it.todo("should sum premiums for multiple different items");
    it.todo("should bundle 3 alike components at special rate of 60G");
    it.todo("should add 50% surcharge for cursed items");
    it.todo("should add 30% surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 10% first insurance surcharge on first contract");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should add 5G processing fee to every premium");
    it.todo("should round amounts in MHPCO's favor (ceiling)");
  });

  describe("Claims", () => {
    it.todo("should reimburse damage minus 100G deductible");
    it.todo("should not pay out if damage is less than deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse dragon material damage at 100%");
    it.todo("should reimburse high enchantment (>= 8) damage at 50%");
    it.todo("should track remaining cap across multiple claims on same policy");
  });
});

