## Step 5: Calculate New APP Mass

New implementation:
```typescript
const computeQuotePremium = (items: any[]): number => {
  const totalBasePremium = items.reduce(
    (sum: number, item: any) => sum + BASE_PREMIUMS[item.type], 0
  );
  return ceilGold(totalBasePremium * 1.10 + PROCESSING_FEE);
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const premium = computeQuotePremium(step.items);
    return { premium };
  });
  return { results };
};
```

- Constants: 9 (100, 60, 80, 40, 25, 25, 1.10, 0, 2) → ×1 = 9
- Bindings: 9 (items, sum, item, totalBasePremium, scenario, step, premium, results, amount) → ×1 = 9
