const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const PROCESSING_FEE = 5;

const ceilGold = (amount: number): number =>
  Math.ceil(parseFloat(amount.toFixed(2)));

const computeQuotePremium = (items: any[]): number => {
  const totalBasePremium = items.reduce(
    (sum: number, item: any) => sum + BASE_PREMIUMS[item.type],
    0
  );
  return ceilGold(totalBasePremium * 1.10 + PROCESSING_FEE);
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const premium = computeQuotePremium(step.items);
    return { premium };
  });
  return { results };
};

