const COMPONENT_TYPES = ["rune", "moonstone"];
const BUNDLE_SIZE = 3;
const BUNDLE_PREMIUM = 60;

const computeQuotePremium = (items: any[]): number => {
  let totalBasePremium = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.includes(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      totalBasePremium += BASE_PREMIUMS[item.type];
    }
  }

  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    const bundles = Math.floor(count / BUNDLE_SIZE);
    const remainder = count % BUNDLE_SIZE;
    totalBasePremium += bundles * BUNDLE_PREMIUM + remainder * BASE_PREMIUMS[type];
  }

  return ceilGold(totalBasePremium * 1.10 + PROCESSING_FEE);
};

