import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting", () => {
    it("should compute base premium for a single sword", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      // base 100 + 10% first insurance = 110 + 5 fee = 115
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should compute base premium for each item type (amulet, staff, potion)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      // base 60 + 10% first insurance = 66 + 5 fee = 71
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should compute base premium for a single component (rune)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 1, cursed: false },
            ],
          },
        ],
      });
      // base 25 * 1.10 = 27.5 → ceil = 28 + 5 fee = 33
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should sum premiums for multiple different items", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      // base: sword 100 + amulet 60 = 160, * 1.10 = 176 + 5 = 181
      expect(result.results[0]).toEqual({ premium: 181 });
    });
    it("should bundle 3 alike components at special rate of 60G", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 1, cursed: false },
              { type: "rune", material: "stone", enchantment: 1, cursed: false },
              { type: "rune", material: "stone", enchantment: 1, cursed: false },
            ],
          },
        ],
      });
      // 3 runes bundled = 60G base, * 1.10 = 66 + 5 = 71
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should add 50% surcharge for cursed items", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: true },
            ],
          },
        ],
      });
      // base 100 + 50% cursed = 150, * 1.10 first insurance = 165 + 5 = 170
      expect(result.results[0]).toEqual({ premium: 170 });
    });
    it("should add 30% surcharge for highly enchanted items (enchantment >= 5)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "oak", enchantment: 5, cursed: false },
            ],
          },
        ],
      });
      // base 80 * 1.30 enchantment = 104, * 1.10 first insurance = 114.4 → ceil 115 + 5 = 120
      expect(result.results[0]).toEqual({ premium: 120 });
    });
    it("should apply 20% loyalty discount for long-standing customers (>= 2 years)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      // base 100, loyalty -20% = 80, multi-contract -15% = 68, + 5 fee = 73
      expect(result.results[0]).toEqual({ premium: 73 });
    });
    it("should apply 10% first insurance surcharge on first contract", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 1, cursed: false },
            ],
          },
        ],
      });
      // base 40 * 1.10 first insurance = 44 + 5 = 49
      expect(result.results[0]).toEqual({ premium: 49 });
    });
    it("should apply 15% discount on each contract after the first", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 1 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      // base 100, no loyalty (1 year < 2), multi-contract * 0.85 = 85 + 5 = 90
      expect(result.results[0]).toEqual({ premium: 90 });
    });
    it("should add 5G processing fee to every premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      // base 60, loyalty *0.80 = 48, multi-contract *0.85 = 40.8, + 5 fee = 45.8, ceil = 46
      expect(result.results[0]).toEqual({ premium: 46 });
    });
    it("should round amounts in MHPCO's favor (ceiling)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 1, cursed: false },
            ],
          },
        ],
      });
      // base 40, loyalty *0.80 = 32, multi-contract *0.85 = 27.2, + 5 = 32.2, ceil = 33
      expect(result.results[0]).toEqual({ premium: 33 });
    });
  });

  describe("Claims", () => {
    it("should reimburse damage minus 100G deductible", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
          {
            op: "claim" as const,
            policy: 0,
            incident: {
              cause: "fire",
              damages: [{ itemType: "sword", amount: 300 }],
            },
          },
        ],
      });
      // damage 300 - 100 deductible = 200 payout, cap = 2*1000 - 200 = 1800
      expect(result.results[1]).toEqual({ payout: 200, remainingCap: 1800 });
    });
    it.todo("should not pay out if damage is less than deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse dragon material damage at 100%");
    it.todo("should reimburse high enchantment (>= 8) damage at 50%");
    it.todo("should track remaining cap across multiple claims on same policy");
  });
});

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const PROCESSING_FEE = 5;

const ceilGold = (amount: number): number =>
  Math.ceil(parseFloat(amount.toFixed(2)));

const COMPONENT_TYPES = ["rune", "moonstone"];
const BUNDLE_SIZE = 3;
const BUNDLE_PREMIUM = 60;

const isComponent = (type: string): boolean =>
  COMPONENT_TYPES.includes(type);

const computeComponentPremium = (count: number, unitPremium: number): number => {
  const bundles = Math.floor(count / BUNDLE_SIZE);
  const remainder = count % BUNDLE_SIZE;
  return bundles * BUNDLE_PREMIUM + remainder * unitPremium;
};

const computeMainItemPremium = (item: any): number => {
  let premium = BASE_PREMIUMS[item.type];
  if (item.cursed) premium *= 1.50;
  if (item.enchantment >= 5) premium *= 1.30;
  return premium;
};

const computeCustomerModifier = (customer: any): number => {
  let modifier = 1;
  if (customer.yearsWithMHPCO === 0) {
    modifier *= 1.10;
  } else {
    if (customer.yearsWithMHPCO >= 2) modifier *= 0.80;
    modifier *= 0.85;
  }
  return modifier;
};

const computeQuotePremium = (items: any[], customer: any): number => {
  let totalItemPremium = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      totalItemPremium += computeMainItemPremium(item);
    }
  }

  for (const type of Object.keys(componentCounts)) {
    totalItemPremium += computeComponentPremium(componentCounts[type], BASE_PREMIUMS[type]);
  }

  return ceilGold(totalItemPremium * computeCustomerModifier(customer) + PROCESSING_FEE);
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const premium = computeQuotePremium(step.items, scenario.customer);
    return { premium };
  });
  return { results };
};

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    include: ['src/**/*.spec.ts'],
