export const processScenario = (scenario: any): any => {
  const policies: any[] = [];
  const results: any[] = [];

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const premium = computeQuotePremium(step.items, scenario.customer);
      policies.push({ items: step.items, remainingCap: 2 * step.items.reduce((sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] || 0), 0) });
      results.push({ premium });
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      const totalDamage = step.incident.damages.reduce((sum: number, d: any) => sum + d.amount, 0);
      const payout = Math.max(0, totalDamage - DEDUCTIBLE);
      policy.remainingCap -= payout;
      results.push({ payout, remainingCap: policy.remainingCap });
    }
  }

  return { results };
};

